import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "How is time duration calculated?", a: "Time duration is calculated by subtracting the start datetime from the end datetime. The difference is expressed in milliseconds, then converted to days, hours, minutes, and seconds. For example: from Jan 1 at 9:00 AM to Jan 3 at 2:30 PM = 2 days, 5 hours, 30 minutes, 0 seconds (or 53.5 hours total)." },
  { q: "What if the end time is before the start time?", a: "If the end datetime is earlier than the start datetime, the duration would be negative - which is not physically meaningful. Make sure your end date/time is set later than your start date/time. This happens commonly when forgetting to adjust the date when the time appears to go backward." },
  { q: "Can I calculate duration across multiple days?", a: "Yes - this calculator uses full datetime inputs (date + time), so it accurately handles durations spanning multiple days, months, or even years. The total is broken down into days + hours + minutes + seconds, and also expressed as total hours and total minutes for easy use in payroll or project calculations." },
  { q: "What is the difference between elapsed time and duration?", a: "Elapsed time refers to how much time has passed from a specific start point to right now. Duration is the length of time between any two arbitrary points. Both measure a span of time, but elapsed time always ends 'now' while duration can measure any past, present, or future interval." },
  { q: "How do I calculate how many days until a future date?", a: "Set the start datetime to today's date and time. Set the end datetime to your target future date. The calculator will show the exact duration in days, hours, minutes, and seconds. Common uses: countdown to event dates, project deadlines, due dates, anniversaries, or contract expiration dates." },
  { q: "How do I calculate time between two dates in business days?", a: "This calculator measures calendar days (including weekends and holidays). For business days, subtract Saturday and Sunday count from the total days. A quick approximation: (calendar days  x  5)  x  7, rounded. For precise business-day counts, you also need to account for public holidays in your jurisdiction." },
  { q: "How many hours are in a year, month, or week?", a: "1 standard year = 8,760 hours = 525,600 minutes. 1 leap year = 8,784 hours. 1 month (30-day) = 720 hours. 1 week = 168 hours = 10,080 minutes. 1 business week (40 hrs) = 40 hours. A standard work year = 2,080 hours (52 weeks  x  40 hrs). These are commonly used in contract and billing calculations." },
  { q: "Why do I get different results for the same dates in different tools?", a: "Time zone handling is the most common cause of discrepancy. If you enter '9:00 AM' without specifying a time zone, different tools may interpret this as local time or UTC. This calculator uses your browser's local time zone for all calculations. For cross-timezone duration tracking, convert both times to UTC first." },
];

const REFERENCE_DURATIONS = [
  ["1 work day", "8 hours", "480 minutes", "28,800 seconds"],
  ["1 work week", "40 hours", "2,400 minutes", "144,000 seconds"],
  ["1 calendar week", "168 hours", "10,080 minutes", "604,800 seconds"],
  ["30-day month", "720 hours", "43,200 minutes", "2,592,000 seconds"],
  ["1 quarter (91 days)", "2,184 hours", "131,040 minutes", "7,862,400 seconds"],
  ["1 year (365 days)", "8,760 hours", "525,600 minutes", "31,536,000 seconds"],
  ["1 leap year (366 days)", "8,784 hours", "527,040 minutes", "31,622,400 seconds"],
];

export default function TimeDurationCalculator() {
  const now = new Date();
  const pad = (n: number) => String(n).padStart(2, "0");
  const defaultStart = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}T${pad(now.getHours())}:00`;
  const defaultEnd = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}T${pad(now.getHours() + 2)}:00`;

  const [start, setStart] = useState(defaultStart);
  const [end, setEnd] = useState(defaultEnd);

  const diffMs = new Date(end).getTime() - new Date(start).getTime();
  const valid = diffMs >= 0 && !isNaN(diffMs);
  const totalSeconds = Math.floor(diffMs / 1000);
  const days = Math.floor(totalSeconds / 86400);
  const hours = Math.floor((totalSeconds % 86400) / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;

  return (
    <>
      <SEOHead
        title="Free Time Duration Calculator Online - Calculate Exact Duration Between Two Times Instantly | CalcHive"
        description="Free online time duration calculator. Calculate the exact duration between two date-times in days, hours, minutes and seconds instantly. 100% free for everyone, no signup required."
        canonical="/time-duration-calculator"
        keywords="free time duration calculator, time difference calculator free online, calculate duration between two times free, days hours minutes calculator free, free elapsed time calculator"
        category="Date & Time Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-950/50 px-3 py-1 rounded-full mb-4 inline-block">Date &amp; Time</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Time Duration Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free time duration calculator to calculate duration between two times free in days, hours, minutes, and seconds. This time difference calculator free online also works as a days hours minutes calculator free and free elapsed time calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 mb-8">
            <div>
              <label className="text-sm font-semibold text-foreground mb-2 block">Start Date &amp; Time</label>
              <input type="datetime-local" value={start} onChange={e => setStart(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm" />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground mb-2 block">End Date &amp; Time</label>
              <input type="datetime-local" value={end} onChange={e => setEnd(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm" />
            </div>
          </div>
          <motion.div key={diffMs} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            {!valid ? (
              <div className="bg-red-50 dark:bg-red-950/50 border border-red-200 dark:border-red-800 rounded-2xl p-6 text-center">
                <p className="text-red-600 dark:text-red-400 font-semibold">End time must be after start time</p>
              </div>
            ) : (
              <>
                <div className="bg-gradient-to-br from-orange-500 to-orange-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                  <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-2">Total Duration</p>
                  <p className="text-3xl font-black text-white tracking-tight" data-testid="result-duration">
                    {days > 0 && `${days}d `}{hours > 0 && `${hours}h `}{minutes > 0 && `${minutes}m `}{seconds}s
                  </p>
                </div>
                <div className="grid grid-cols-4 gap-3 mb-3">
                  {[{ label: "Days", value: days }, { label: "Hours", value: hours }, { label: "Minutes", value: minutes }, { label: "Seconds", value: seconds }].map(({ label, value }) => (
                    <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                      <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                      <p className="text-xl font-extrabold text-foreground">{value}</p>
                    </div>
                  ))}
                </div>
                <div className="mt-3 grid grid-cols-2 gap-3">
                  {[
                    { label: "Total Hours (decimal)", value: (totalSeconds / 3600).toFixed(2) },
                    { label: "Total Minutes", value: Math.floor(totalSeconds / 60).toLocaleString() },
                  ].map(({ label, value }) => (
                    <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 text-center">
                      <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                      <p className="text-base font-extrabold text-foreground">{value}</p>
                    </div>
                  ))}
                </div>
              </>
            )}
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Time Duration Between Two Date-Times for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Duration (ms) = End DateTime - Start DateTime</p>
            <p>Total Seconds = Duration  x  1000</p>
            <p>Days = floor(Total Seconds  x  86,400)</p>
            <p>Hours = floor((Total Seconds mod 86,400)  x  3,600)</p>
            <p>Minutes = floor((Total Seconds mod 3,600)  x  60)</p>
            <p>Seconds = Total Seconds mod 60</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Exact Days Hours Minutes and Seconds Between Times</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Period", "Total Hours", "Total Minutes", "Total Seconds"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {REFERENCE_DURATIONS.map(([period, hrs, mins, secs]) => (
                  <tr key={period} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{period}</td>
                    <td className="py-2.5 px-4 text-orange-600 dark:text-orange-400 font-bold">{hrs}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{mins}</td>
                    <td className="py-2.5 px-4 font-mono text-muted-foreground text-xs">{secs}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Time Difference Calculator for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free date and time tool on any device to compare schedules, track durations, and get instant results without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/time-duration-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


